Window.Resources.MotionClip:
@parameter Movement: MotionSpec<float>;
@parallel
{
    @animate with Movement
    {
        @from { $part.LabTarget.TranslateX = 0; }
        @to { $part.LabTarget.TranslateX = 430; }
    }
    @animate with $LabScaleSpring
    {
        @from { $part.LabTarget.Scale = 0.72; }
        @to { $part.LabTarget.Scale = 1; }
    }
    @animate with $LabOpacityTween
    {
        @from { $part.LabTarget.Opacity = 0.35; }
        @to { $part.LabTarget.Opacity = 1; }
    }
}

Window.Resources.Aspect:
@handle Movement;
@on TweenSpecRequested { @run $LabTravel(Movement = Tween(820ms, Emphasized)) as Movement; }
@on SpringLooseRequested { @run $LabTravel(Movement = Spring(280, 20)) as Movement; }
@on SpringBalancedRequested { @run $LabTravel(Movement = Spring(280, 38)) as Movement; }
@on SpringFirmRequested { @run $LabTravel(Movement = Spring(280, 60)) as Movement; }
@on SpringQuickLooseRequested { @run $LabTravel(Movement = Spring(520, 20)) as Movement; }
@on SpringQuickBalancedRequested { @run $LabTravel(Movement = Spring(520, 38)) as Movement; }
@on SpringQuickFirmRequested { @run $LabTravel(Movement = Spring(520, 60)) as Movement; }
@on SpringTightLooseRequested { @run $LabTravel(Movement = Spring(820, 20)) as Movement; }
@on SpringTightBalancedRequested { @run $LabTravel(Movement = Spring(820, 38)) as Movement; }
@on SpringTightFirmRequested { @run $LabTravel(Movement = Spring(820, 60)) as Movement; }

@default { FontFamily = "Cascadia Mono SemiBold"; FontSize = 11; Background = $LimeBrush; Foreground = $InkBrush; BorderBrush = $LimeBrush; BorderThickness = "1"; Padding = "18,11,18,11"; }
@when IsMouseOver
{
    @if IsMouseOver == true
    {
        @animate with $LabHoverTween
        {
            @from { Background = current; BorderBrush = current; }
            @to { Background = $CyanBrush; BorderBrush = $CyanBrush; }
        }
    }
    @if IsMouseOver == false
    {
        @animate with $LabHoverTween
        {
            @from { Background = current; BorderBrush = current; }
            @to { Background = $LimeBrush; BorderBrush = $LimeBrush; }
        }
    }
}
